/**
 * Type definitions for the Email Classification Engine
 *
 * This module exports all entity types for the sophisticated 9-stage
 * classification pipeline with parallel processing capabilities.
 */

// Core email processing entities
export * from './email-message';
export * from './classification-session';
export * from './classification-result';

// Explainability and audit trail entities
export * from './explainability-trace';
export * from './score-breakdown';
export * from './attribute-context';

// Configuration and schema validation
export * from './category-configuration';

// Classification results and labels
export * from './classification-result';

// Pipeline stage names
export * from './stage-name';

